+    #[test]
+    fn policy_rules_integrated_into_authorize_deny() {
+        let rules = PolicyRulesConfig {
+            enabled: true,
+            rules: vec![PolicyRule {
+                id: "deny-robot-close".to_string(),
+                description: None,
+                priority: 100,
+                match_on: PolicyRuleMatch {
